let produtoAtual = null;
let html5QrCode = null;

// Função para formatar valores em Moeda Real
function formatar(v) { 
    return v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }); 
}

// Função de Busca e Listagem
function buscar(codigo = null) {
    const termo = (codigo || document.getElementById('skuInput').value).trim().toUpperCase();
    const nomeGrupoFiltro = document.getElementById('groupSelect').value;
    const listDiv = document.getElementById('groupResults');
    
    document.getElementById('error').style.display = 'none';
    document.getElementById('result').style.display = 'none';
    listDiv.style.display = 'none';
    listDiv.innerHTML = '';

    // Se campo vazio e grupo selecionado, mostra todos os produtos daquele grupo
    if (!termo && nomeGrupoFiltro) {
        const produtosNoGrupo = estoque.filter(i => i.nomeGrupo === nomeGrupoFiltro);
        if (produtosNoGrupo.length > 0) {
            listDiv.style.display = 'block';
            produtosNoGrupo.forEach(p => {
                const item = document.createElement('div');
                item.className = 'group-item';
                item.innerText = `${p.r} - ${p.d}`;
                item.onclick = () => { exibirProduto(p); listDiv.style.display = 'none'; };
                listDiv.appendChild(item);
            });
        } else {
            document.getElementById('error').style.display = 'block';
        }
        return;
    }

    if (!termo) return;

    // Busca por Referência ou Código de Barras
    const p = estoque.find(i => 
        (i.r.toUpperCase() === termo || i.b === termo) && 
        (nomeGrupoFiltro === "" || i.nomeGrupo === nomeGrupoFiltro)
    );

    if (p) {
        stopScanner();
        exibirProduto(p);
    } else {
        document.getElementById('error').style.display = 'block';
    }
}

// Preenche os campos do produto encontrado
function exibirProduto(p) {
    produtoAtual = p;
    document.getElementById('result').style.display = 'block';
    document.getElementById('prodDesc').innerText = p.d;
    document.getElementById('prodRef').innerText = p.r;
    document.getElementById('skuInput').value = p.r;
    
    // Regra Automática: Se for OUTLET, começa com 50%
    const descInicial = (p.nomeGrupo === "OUTLET") ? 50 : 0;
    document.getElementById('manualDiscount').value = descInicial;
    
    recalcularPreco();
}

// Calcula o preço com base no desconto manual
function recalcularPreco() {
    if(!produtoAtual) return;
    const descManual = parseFloat(document.getElementById('manualDiscount').value) || 0;
    const precoOriginal = produtoAtual.v;
    const precoFinal = precoOriginal * (1 - descManual / 100);

    const txtAntigo = document.getElementById('precoAntigo');
    const txtAtual = document.getElementById('precoAtual');
    const tag = document.getElementById('tagDesconto');

    if(descManual > 0) {
        txtAntigo.innerText = "De: " + formatar(precoOriginal);
        txtAtual.innerText = formatar(precoFinal);
        tag.style.display = 'block';
        tag.innerHTML = `🔥 Referencia com ${descManual}% de desconto 🔥`;
    } else {
        txtAntigo.innerText = "Preço de Venda:";
        txtAtual.innerText = formatar(precoOriginal);
        tag.style.display = 'none';
    }
}

// Inicia o Scanner (Câmara)
function startScanner() {
    html5QrCode = new Html5Qrcode("reader");
    document.getElementById('scanBtn').style.display = 'none';
    
    const config = { fps: 20, qrbox: { width: 250, height: 150 } };

    html5QrCode.start({ facingMode: "environment" }, config, (text) => {
        if(navigator.vibrate) navigator.vibrate(100); // Vibra ao ler
        buscar(text);
    }).catch(err => alert("Erro ao abrir câmara. Verifique as permissões."));
}

// Pára o Scanner
function stopScanner() {
    if(html5QrCode && html5QrCode.isScanning) {
        html5QrCode.stop().then(() => {
            document.getElementById('scanBtn').style.display = 'block';
        });
    }
}